      <div className={`absolute left-0 top-0 bottom-0 w-2.5 transition-colors duration-500 ${isPositivated ? 'bg-emerald-500' : 'bg-slate-100 dark:bg-slate-800'}`}></div>

      <div className="p-6 pl-8 flex justify-between items-center cursor-pointer select-none" onClick={() => onUpdateState({ isExpanded: !isExpanded })}>
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2 mb-1.5">
             <h4 className={`font-black text-[15px] truncate uppercase tracking-tight transition-colors ${isPositivated ? 'text-emerald-700 dark:text-emerald-400' : 'text-slate-900 dark:text-white'}`}>{client.name}</h4>
          </div>
          <div className="flex items-center gap-x-2 text-[10px] font-black text-slate-400 uppercase tracking-widest">
             <span className="bg-slate-100 dark:bg-slate-800 px-1.5 py-0.5 rounded-md text-slate-500">#{client.code}</span>
             <span>•</span>
             <span className="truncate">{client.city}</span>
          </div>
        </div>
        <div className={`transition-transform duration-500 ${isExpanded ? 'rotate-180 text-brand-500' : 'text-slate-300'}`}>
           <ChevronDown size={24}/>
        </div>
      </div>

      {isExpanded && (
        <div className="border-t border-slate-50 dark:border-slate-800 animate-in slide-in-from-top-6">
           <div className="grid grid-cols-1 md:grid-cols-2 divide-y md:divide-y-0 md:divide-x divide-slate-100 dark:divide-slate-800">
              {/* Checklist */}
              <div className="p-8">
                 <h5 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-5">Ativação</h5>
                 <div className="grid grid-cols-2 gap-3">
                    {tasks.map(t => (
                      <button key={t.id} onClick={() => toggleTask(t.label)} className={`p-4 rounded-2xl border font-black text-[10px] uppercase transition-all flex items-center justify-center gap-2 ${t.checked ? 'bg-brand-600 border-brand-600 text-white shadow-lg' : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 text-slate-400'}`}>
                         {t.checked && <Check size={14}/>} {t.label}
                      </button>
                    ))}
                 </div>
              </div>

              {/* Vendas */}
              <div className="p-8 bg-slate-50/30 dark:bg-slate-900/50">
                 <div className="flex justify-between items-center mb-5">
                    <h5 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Atendimento Atual</h5>
                    <div className="text-xl font-black text-brand-600 tabular-nums">
                      R$ {parseFloat(uiState?.saleValue || '0').toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                    </div>
                 </div>

                 <div className="flex gap-2 mb-5">
                    <input type="number" placeholder="0,00" value={currentSaleInput} onChange={e => setCurrentSaleInput(e.target.value)} className="flex-1 p-4 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-2xl text-base font-black outline-none focus:ring-2 focus:ring-brand-500" />
                 </div>

                 <div className="grid grid-cols-2 gap-3 mb-6">
                    <button onClick={() => handleAddSale('palm')} className="py-4 bg-slate-900 text-white rounded-2xl font-black text-[10px] uppercase flex flex-col items-center gap-1 shadow-lg">+ PALM</button>
                    <button onClick={() => handleAddSale('site')} className="py-4 bg-brand-600 text-white rounded-2xl font-black text-[10px] uppercase flex flex-col items-center gap-1 shadow-lg">+ SITE</button>
                 </div>

                 {history.length > 0 && (
                   <div className="space-y-2">
                     <div className="flex justify-between items-center mb-2">
                        <span className="text-[9px] font-black text-slate-400 uppercase">Resumo da Visita</span>
                        <button onClick={handleClearSales} className="text-[9px] font-black text-red-500 uppercase">Limpar</button>
                     </div>
                     <div className="max-h-32 overflow-y-auto space-y-2 pr-1 custom-scrollbar">
                        {history.map((op, idx) => (
                          <div key={idx} className="flex justify-between items-center bg-white dark:bg-slate-800 p-3 rounded-xl border border-slate-100 dark:border-slate-700">
                             <span className="text-[10px] font-black text-slate-600">PEDIDO #{idx + 1} ({parseFloat(op.palm) > 0 ? 'PALM' : 'SITE'})</span>
                             <span className="text-[10px] font-black text-brand-600">R$ {parseFloat(parseFloat(op.palm) > 0 ? op.palm : op.site).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                          </div>
                        ))}
                     </div>
                   </div>
                 )}
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { User, ActivationLog, Client, ClientUIState, TaskState } from '../types';
import { ChevronDown, Search, MapPin, Sparkles, Info, History as HistoryIcon, RefreshCw, Navigation, Smartphone, Globe, Check, Compass, Ban, ArrowDownAZ, Navigation2, Flame, Snowflake, Loader2, Map as MapIcon, CalendarDays, CheckCircle2, LayoutGrid, Trash2, Plus, X } from 'lucide-react';
import { useStore } from '../contexts/StoreContext';
// @ts-ignore
import L from 'leaflet';

interface LogActivationProps {
  user: User;
  clients: Client[];
  clientStates: Record<string, ClientUIState>;
  onUpdateClientState: (clientId: string, updates: Partial<ClientUIState>) => void;
  onSave: (log: Omit<ActivationLog, 'id'>) => void;
}

const calculateDistance = (lat1: number, lon1: number, lat2: number, lon2: number) => {
  const R = 6371;
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLon = (lon2 - lon1) * Math.PI / 180;
  const a = Math.sin(dLat / 2) * Math.sin(dLat / 2) + Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) * Math.sin(dLon / 2) * Math.sin(dLon / 2);
  return R * (2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a)));
};

const getWeekNumber = (date: Date) => {
  const d = new Date(Date.UTC(date.getFullYear(), date.getMonth(), date.getDate()));
  const dayNum = d.getUTCDay() || 7;
  d.setUTCDate(d.getUTCDate() + 4 - dayNum);
  const yearStart = new Date(Date.UTC(d.getUTCFullYear(), 0, 1));
  return Math.ceil((((d.getTime() - yearStart.getTime()) / 86400000) + 1) / 7);
};

export const LogActivation: React.FC<LogActivationProps> = ({ 
  user, clients, clientStates, onUpdateClientState, onSave 
}) => {
  const { state } = useStore(); 
  const [searchTerm, setSearchTerm] = useState('');
  const calendarDays = ['Domingo', 'Segunda-feira', 'Terça-feira', 'Quarta-feira', 'Quinta-feira', 'Sexta-feira', 'Sábado'];
  const todayName = useMemo(() => calendarDays[new Date().getDay()], []);
  const [selectedDay, setSelectedDay] = useState<string | 'GERAL'>(todayName);
  const [statusFilter, setStatusFilter] = useState<'all' | 'pending' | 'done' | 'priority'>('all');
  const [sortMode, setSortMode] = useState<'name' | 'distance'>('name');
  const [showMapModal, setShowMapModal] = useState(false);
  const [userLocation, setUserLocation] = useState<{lat: number, lng: number} | null>(null);
  const [isSyncingLocation, setIsSyncingLocation] = useState(false);

  const mapRef = useRef<any>(null);
  const mapContainerRef = useRef<HTMLDivElement>(null);

  const currentWeekNum = useMemo(() => getWeekNumber(new Date()), []);
  const isEvenWeek = currentWeekNum % 2 === 0;

  const syncLocation = useCallback(() => {
    if (!navigator.geolocation) return;
    setIsSyncingLocation(true);
    navigator.geolocation.getCurrentPosition(
      (pos) => {
        setUserLocation({ lat: pos.coords.latitude, lng: pos.coords.longitude });
        setIsSyncingLocation(false);
      },
      () => setIsSyncingLocation(false),
      { enableHighAccuracy: true }
    );
  }, []);

  useEffect(() => {
    syncLocation();
  }, [syncLocation]);

  const isClientPositivated = useCallback((clientId: string) => {
    const s = clientStates[clientId];
    return s ? (s.tasks?.some(t => t.checked) || parseFloat(s.saleValue || '0') > 0 || s.isSaved) : false;
  }, [clientStates]);

  const filteredClients = useMemo(() => {
    return clients.filter(client => 
      client.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      client.code.includes(searchTerm)
    );
  }, [clients, searchTerm]);

  const groupedClients = useMemo(() => {
    return filteredClients.reduce((acc, client) => {
      const day = client.visitDay || 'Sem dia definido';
      if (client.frequency === 'odd_week' && isEvenWeek) return acc;
      if (client.frequency === 'even_week' && !isEvenWeek) return acc;
      if (!acc[day]) acc[day] = [];
      acc[day].push(client);
      return acc;
    }, {} as Record<string, Client[]>);
  }, [filteredClients, isEvenWeek]);

  const getLastPurchaseInfo = useCallback((clientName: string) => {
    const historyLogs = state.salesLogs.filter(s => s.clientName === clientName).map(s => ({ date: s.timestamp, amount: s.amount }));
    const recentLogs = state.activationLogs.filter(a => a.clientName === clientName && (a.saleValue || 0) > 0).map(a => ({ date: a.timestamp, amount: a.saleValue || 0 }));
    const allSales = [...historyLogs, ...recentLogs].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

    if (allSales.length === 0) return null;
    const lastSale = allSales[0];
    const diffDays = Math.ceil(Math.abs(new Date().getTime() - new Date(lastSale.date).getTime()) / (1000 * 60 * 60 * 24));
    const avg = allSales.reduce((acc, curr) => acc + curr.amount, 0) / allSales.length;

    return { amount: lastSale.amount, daysAgo: diffDays, average: avg };
  }, [state.salesLogs, state.activationLogs]);

  const selectedDayClientsTotal = useMemo(() => {
    if (selectedDay === 'GERAL') return filteredClients;
    return groupedClients[selectedDay] || [];
  }, [selectedDay, groupedClients, filteredClients]);

  const clientsWithLocation = useMemo(() => {
    return selectedDayClientsTotal.filter(c => c.lat && c.lng);
  }, [selectedDayClientsTotal]);

  const nextClient = useMemo(() => {
    if (!userLocation || selectedDayClientsTotal.length === 0) return null;
    const pending = selectedDayClientsTotal.filter(c => !isClientPositivated(c.id) && c.lat && c.lng);
    if (pending.length === 0) return null;

    return pending.reduce((prev, curr) => {
      const distPrev = calculateDistance(userLocation.lat, userLocation.lng, prev.lat!, prev.lng!);
      const distCurr = calculateDistance(userLocation.lat, userLocation.lng, curr.lat!, curr.lng!);
      return distPrev < distCurr ? prev : curr;
    });
  }, [userLocation, selectedDayClientsTotal, isClientPositivated]);

  const clientsToRender = useMemo(() => {
    let list = [...selectedDayClientsTotal];

    if (sortMode === 'distance' && userLocation) {
      list.sort((a, b) => {
        if (!a.lat || !a.lng) return 1;
        if (!b.lat || !b.lng) return -1;
        const distA = calculateDistance(userLocation.lat, userLocation.lng, a.lat, a.lng);
        const distB = calculateDistance(userLocation.lat, userLocation.lng, b.lat, b.lng);
        return distA - distB;
      });
    } else {
      list.sort((a, b) => a.name.localeCompare(b.name));
    }

    if (statusFilter === 'pending') list = list.filter(c => !isClientPositivated(c.id));
    if (statusFilter === 'done') list = list.filter(c => isClientPositivated(c.id));
    if (statusFilter === 'priority') list = list.filter(c => {
      const info = getLastPurchaseInfo(c.name);
      return info && (info.daysAgo > 45 || info.amount > 2000);
    });
    return list;
  }, [selectedDayClientsTotal, statusFilter, sortMode, userLocation, isClientPositivated, getLastPurchaseInfo]);

  // Leaflet Logic
  useEffect(() => {
    if (showMapModal && mapContainerRef.current && !mapRef.current) {
      const initialView: [number, number] = clientsWithLocation.length > 0 
        ? [clientsWithLocation[0].lat!, clientsWithLocation[0].lng!] 
        : (userLocation ? [userLocation.lat, userLocation.lng] : [-23.5505, -46.6333]);

      mapRef.current = L.map(mapContainerRef.current).setView(initialView, 14);

      L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
        attribution: '&copy; OpenStreetMap contributors'
      }).addTo(mapRef.current);

      const markersGroup = L.featureGroup().addTo(mapRef.current);

      // User location marker
      if (userLocation) {
        L.marker([userLocation.lat, userLocation.lng], {
          icon: L.divIcon({
            className: 'custom-div-icon',
            html: `<div style="background-color: #4f46e5; width: 15px; height: 15px; border-radius: 50%; border: 3px solid white; box-shadow: 0 0 10px rgba(0,0,0,0.3);"></div>`,
            iconSize: [15, 15],
            iconAnchor: [7, 7]
          })
        }).addTo(mapRef.current).bindPopup('Sua localização atual');
      }

      // Client markers
      clientsWithLocation.forEach(c => {
        const isDone = isClientPositivated(c.id);
        const marker = L.marker([c.lat!, c.lng!], {
          icon: L.divIcon({
            className: 'custom-div-icon',
            html: `<div style="background-color: ${isDone ? '#10b981' : '#4f46e5'}; width: 24px; height: 24px; border-radius: 50%; display: flex; align-items: center; justify-content: center; color: white; font-weight: bold; border: 2px solid white; box-shadow: 0 2px 5px rgba(0,0,0,0.2);">
                    <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round" stroke-linejoin="round"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"></path><circle cx="12" cy="10" r="3"></circle></svg>
                   </div>`,
            iconSize: [24, 24],
            iconAnchor: [12, 12]
          })
        }).addTo(markersGroup);

        marker.bindPopup(`
          <div style="padding: 5px;">
            <strong style="display: block; font-size: 14px; margin-bottom: 4px;">${c.name}</strong>
            <p style="margin: 0 0 8px 0; font-size: 12px; color: #666;">Cód: ${c.code} | Status: ${isDone ? 'Visitado' : 'Pendente'}</p>
            <button onclick="window.open('https://www.google.com/maps/dir/?api=1&destination=${c.lat},${c.lng}')" style="width: 100%; background: #4f46e5; color: white; border: none; padding: 6px; border-radius: 4px; font-weight: bold; cursor: pointer; font-size: 11px;">ABRIR GPS</button>
          </div>
        `);
      });

      if (clientsWithLocation.length > 0) {
        mapRef.current.fitBounds(markersGroup.getBounds().pad(0.1));
      }
    }

    return () => {
      if (mapRef.current) {
        mapRef.current.remove();
        mapRef.current = null;
      }
    };
  }, [showMapModal, clientsWithLocation, userLocation, isClientPositivated]);

  return (
    <div className="max-w-3xl mx-auto space-y-5 pb-24 animate-in fade-in duration-500">
      {/* Header Roteiro */}
      <div className="bg-white dark:bg-slate-900/80 backdrop-blur-md p-6 rounded-[2.5rem] border border-slate-200 dark:border-slate-800 shadow-sm overflow-hidden relative">
        <div className="absolute top-0 right-0 w-32 h-32 bg-brand-500/5 rounded-full -mr-16 -mt-16 blur-3xl"></div>
        <div className="flex justify-between items-end relative z-10">
          <div>
            <h2 className="text-2xl font-black text-slate-900 dark:text-white tracking-tight leading-none">
              {selectedDay === 'GERAL' ? 'Carteira Geral' : 'Roteiro'}
            </h2>
            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-[0.2em] mt-2 flex items-center gap-1.5">
              {selectedDay === 'GERAL' ? (
                <><LayoutGrid size={12} className="text-brand-500" /> Visão Completa</>
              ) : (
                <><CalendarDays size={12} className="text-brand-500" /> {selectedDay} • Semana {isEvenWeek ? 'Par' : 'Ímpar'}</>
              )}
            </p>
          </div>
          <div className="text-right">
             <div className="bg-brand-50 dark:bg-brand-900/30 px-3 py-1 rounded-full mb-1 inline-block">
                <span className="text-sm font-black text-brand-600 dark:text-brand-400 tabular-nums">
                  {selectedDayClientsTotal.filter(c => isClientPositivated(c.id)).length}/{selectedDayClientsTotal.length}
                </span>
             </div>
             <p className="text-[9px] text-slate-400 font-black uppercase tracking-widest">Cobertura</p>
          </div>
        </div>
      </div>

      {/* Sugestão Inteligente Próximo PDV */}
      {nextClient && (
        <div className="bg-brand-600 dark:bg-brand-500 p-5 rounded-[2rem] shadow-xl shadow-brand-500/20 flex items-center gap-4 animate-in slide-in-from-left-4 relative overflow-hidden group">
           <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/5 to-transparent -translate-x-full group-hover:translate-x-full transition-transform duration-1000"></div>
           <div className="w-12 h-12 bg-white/20 rounded-2xl flex items-center justify-center backdrop-blur-md border border-white/20">
              <Compass size={24} className="text-white animate-spin-slow" />
           </div>
           <div className="flex-1 min-w-0">
              <p className="text-[10px] font-black text-white/70 uppercase tracking-widest">Próxima Parada Recomendada</p>
              <h4 className="text-sm font-black text-white truncate">{nextClient.name}</h4>
           </div>
           <button 
             onClick={() => window.open(`https://www.google.com/maps/dir/?api=1&destination=${nextClient.lat},${nextClient.lng}`)} 
             className="bg-white text-brand-600 p-3.5 rounded-2xl shadow-lg active:scale-90 transition-transform"
           >
              <Navigation size={20} />
           </button>
        </div>
      )}

      {/* Seletor de Dias Horizontal */}
      <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide -mx-4 px-4">
         {calendarDays.map((day) => {
            const isActive = selectedDay === day;
            const count = (groupedClients[day] || []).length;
            return (
              <button 
                key={day} 
                onClick={() => setSelectedDay(day)} 
                className={`shrink-0 flex flex-col items-center justify-center min-w-[70px] h-[75px] rounded-2xl border transition-all duration-300 ${isActive ? 'bg-slate-900 dark:bg-brand-600 text-white border-slate-900 dark:border-brand-500 shadow-lg scale-105' : 'bg-white dark:bg-slate-900 text-slate-400 border-slate-200 dark:border-slate-800 hover:border-brand-300'}`}
              >
                 <span className="text-[9px] font-black uppercase mb-1">{day.substring(0, 3)}</span>
                 <span className="text-lg font-black tracking-tighter">{count}</span>
                 {count > 0 && <div className={`w-1 h-1 rounded-full mt-1 ${isActive ? 'bg-white' : 'bg-brand-500'}`}></div>}
              </button>
            );
         })}
         <button 
           onClick={() => setSelectedDay('GERAL')} 
           className={`shrink-0 flex flex-col items-center justify-center min-w-[70px] h-[75px] rounded-2xl border transition-all duration-300 ${selectedDay === 'GERAL' ? 'bg-emerald-600 text-white border-emerald-500 shadow-lg scale-105' : 'bg-slate-100 dark:bg-slate-800 text-slate-500 border-slate-200 dark:border-slate-700 hover:border-emerald-300'}`}
         >
            <LayoutGrid size={16} className="mb-1" />
            <span className="text-[9px] font-black uppercase">Geral</span>
            <span className="text-lg font-black tracking-tighter">{filteredClients.length}</span>
         </button>
      </div>

      {/* Filtros e Busca */}
      <div className="sticky top-2 z-30">
        <div className="bg-white/90 dark:bg-slate-900/95 backdrop-blur-xl p-3 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-xl space-y-3">
          <div className="flex gap-2">
             <div className="relative flex-1">
               <Search size={16} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-slate-400" />
               <input 
                type="text" 
                placeholder="Pesquisar PDV..." 
                value={searchTerm} 
                onChange={(e) => setSearchTerm(e.target.value)} 
                className="w-full pl-10 pr-4 py-3 bg-slate-100 dark:bg-slate-800 border-none rounded-xl text-sm font-bold outline-none placeholder-slate-400 focus:ring-2 focus:ring-brand-500 transition-all" 
               />
             </div>
             <button 
              onClick={() => { setSortMode(prev => prev === 'name' ? 'distance' : 'name'); if(sortMode === 'name') syncLocation(); }} 
              className={`p-3.5 rounded-xl transition-all ${sortMode === 'distance' ? 'bg-brand-100 dark:bg-brand-900/50 text-brand-600 dark:text-brand-400 ring-2 ring-brand-500/20' : 'bg-slate-100 dark:bg-slate-800 text-slate-400 hover:bg-slate-200 dark:hover:bg-slate-700'}`}
              title="Ordenar por distância"
             >
                {sortMode === 'distance' ? <Navigation2 size={20} fill="currentColor" /> : <ArrowDownAZ size={20} />}
             </button>
             <button 
                onClick={() => setShowMapModal(true)} 
                className="p-3.5 bg-brand-600 text-white rounded-xl shadow-lg shadow-brand-500/20 active:scale-95 transition-all flex items-center gap-2"
                title="Mapa de Clientes da Rota"
             >
                <MapIcon size={20}/>
                <span className="text-[10px] font-black uppercase hidden sm:inline">Mapa da Rota</span>
             </button>
          </div>
          <div className="flex gap-2 overflow-x-auto scrollbar-hide no-tap-highlight">
              {[
                {id: 'all', label: 'Tudo', icon: CheckCircle2}, 
                {id: 'priority', label: '🔥 Críticos', icon: Flame}, 
                {id: 'pending', label: 'Pendentes', icon: RefreshCw}, 
                {id: 'done', label: 'Concluídos', icon: Check}
              ].map(f => (
                <button 
                  key={f.id} 
                  onClick={() => setStatusFilter(f.id as any)} 
                  className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all whitespace-nowrap flex items-center gap-2 ${statusFilter === f.id ? 'bg-brand-600 text-white shadow-md scale-95' : 'bg-slate-50 dark:bg-slate-800 text-slate-500 hover:bg-slate-100 dark:hover:bg-slate-700'}`}
                >
                  <f.icon size={12} /> {f.label}
                </button>
              ))}
          </div>
        </div>
      </div>

      {/* Lista de Clientes */}
      <div className="space-y-4">
        {clientsToRender.length > 0 ? (
          clientsToRender.map((client) => (
            <ClientActivationCard 
              key={client.id} 
              client={client} 
              user={user}
              userLocation={userLocation}
              uiState={clientStates[client.id]}
              // FIX: Added the missing second argument `state` to `getClientHealth` call.
              health={getClientHealth(client.name, state)}
              lastPurchaseInfo={getLastPurchaseInfo(client.name)}
              onUpdateState={(updates) => onUpdateClientState(client.id, updates)}
              onSave={onSave}
            />
          ))
        ) : (
          <div className="py-24 text-center bg-white dark:bg-slate-900 rounded-[2.5rem] border border-dashed border-slate-200 dark:border-slate-800">
            <div className="w-20 h-20 bg-slate-50 dark:bg-slate-800 rounded-full flex items-center justify-center mx-auto mb-4 border border-slate-100 dark:border-slate-700">
