  const isExpanded = uiState?.isExpanded || false;
  const isPositivated = uiState?.tasks?.some(t => t.checked) || parseFloat(uiState?.saleValue || '0') > 0 || uiState?.isSaved;
  const history = uiState?.history || [];

  const industries = useMemo(() => user.industries || ['UNILEVER', 'BAUDUCCO', 'MELITTA'], [user.industries]);
  const tasks = useMemo(() => {
    return industries.map((ind, i) => {
      const saved = uiState?.tasks?.find(t => t.label === ind);
      return { id: `t-${i}`, label: ind, checked: saved?.checked || false };
    });
  }, [industries, uiState?.tasks]);

  const toggleTask = (label: string) => {
    const newTasks = tasks.map(t => t.label === label ? { ...t, checked: !t.checked } : t);
