    const newOperation = { 
      palm: type === 'palm' ? val.toString() : '0', 
      site: type === 'site' ? val.toString() : '0' 
    };
    const newHistory = [...history, newOperation];

    onUpdateState({ 
      saleValuePalm: newPalm.toString(), 
      saleValueSite: newSite.toString(), 
