const ClientActivationCard: React.FC<{ 
  client: Client; user: User; uiState: ClientUIState | undefined; 
  userLocation: {lat: number, lng: number} | null;
  health: { status: string; trend: number[] }; 
  lastPurchaseInfo: any;
  onUpdateState: (updates: Partial<ClientUIState>) => void; onSave: (log: Omit<ActivationLog, 'id'>) => void;
}> = ({ client, user, uiState, userLocation, health, lastPurchaseInfo, onUpdateState, onSave }) => {
  const [currentSaleInput, setCurrentSaleInput] = useState('');

  const isExpanded = uiState?.isExpanded || false;
  const isPositivated = uiState?.tasks?.some(t => t.checked) || parseFloat(uiState?.saleValue || '0') > 0 || uiState?.isSaved;
  const history = uiState?.history || [];

  const industries = useMemo(() => user.industries || ['UNILEVER', 'BAUDUCCO', 'MELITTA'], [user.industries]);
  const tasks = useMemo(() => {
    return industries.map((ind, i) => {
      const saved = uiState?.tasks?.find(t => t.label === ind);
      return { id: `t-${i}`, label: ind, checked: saved?.checked || false };
    });
  }, [industries, uiState?.tasks]);

  const toggleTask = (label: string) => {
    const newTasks = tasks.map(t => t.label === label ? { ...t, checked: !t.checked } : t);
    onUpdateState({ tasks: newTasks, isSaved: true });
  };

  const handleAddSale = (type: 'palm' | 'site') => {
    const val = parseFloat(currentSaleInput.replace(',', '.')) || 0;
    if (val <= 0) return;

    const currentPalm = parseFloat(uiState?.saleValuePalm || '0');
    const currentSite = parseFloat(uiState?.saleValueSite || '0');

    const newPalm = type === 'palm' ? currentPalm + val : currentPalm;
    const newSite = type === 'site' ? currentSite + val : currentSite;
    const newTotal = newPalm + newSite;

    const newOperation = { 
      palm: type === 'palm' ? val.toString() : '0', 
      site: type === 'site' ? val.toString() : '0' 
    };
    const newHistory = [...history, newOperation];

    onUpdateState({ 
      saleValuePalm: newPalm.toString(), 
      saleValueSite: newSite.toString(), 
      saleValue: newTotal.toString(),
      history: newHistory,
      isSaved: true
    });

    setCurrentSaleInput('');
  };

  const handleClearSales = () => {
    if (confirm("Deseja realmente limpar os lançamentos desta visita?")) {
        onUpdateState({ 
            saleValuePalm: '0', 
            saleValueSite: '0', 
            saleValue: '0',
            history: [],
            isSaved: false
        });
    }
  };

  return (
    <div className={`bg-white dark:bg-slate-900 border rounded-[2.5rem] overflow-hidden transition-all duration-500 relative ${isExpanded ? 'ring-2 ring-brand-500 shadow-2xl scale-[1.02] z-20 translate-y-[-4px]' : 'border-slate-200 dark:border-slate-800 shadow-sm'}`}>
      <div className={`absolute left-0 top-0 bottom-0 w-2.5 transition-colors duration-500 ${isPositivated ? 'bg-emerald-500' : 'bg-slate-100 dark:bg-slate-800'}`}></div>

      <div className="p-6 pl-8 flex justify-between items-center cursor-pointer select-none" onClick={() => onUpdateState({ isExpanded: !isExpanded })}>
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2 mb-1.5">
             <h4 className={`font-black text-[15px] truncate uppercase tracking-tight transition-colors ${isPositivated ? 'text-emerald-700 dark:text-emerald-400' : 'text-slate-900 dark:text-white'}`}>{client.name}</h4>
             {isPositivated && <CheckCircle2 size={16} className="text-emerald-500" />}
          </div>
          <div className="flex items-center gap-x-2 text-[10px] font-black text-slate-400 uppercase tracking-widest">
             <span className="bg-slate-100 dark:bg-slate-800 px-1.5 py-0.5 rounded-md text-slate-500">#{client.code}</span>
             <span>•</span>
             <span className="truncate">{client.city}</span>
          </div>
        </div>
        <div className={`transition-transform duration-500 ${isExpanded ? 'rotate-180 text-brand-500' : 'text-slate-300'}`}>
           <ChevronDown size={24}/>
        </div>
      </div>

      {isExpanded && (
        <div className="border-t border-slate-50 dark:border-slate-800 animate-in slide-in-from-top-6">
           <div className="grid grid-cols-1 md:grid-cols-2 divide-y md:divide-y-0 md:divide-x divide-slate-100 dark:divide-slate-800">
              <div className="p-8">
                 <h5 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-5">Ativação de Indústrias</h5>
                 <div className="grid grid-cols-2 gap-3">
                    {tasks.map(t => (
                      <button key={t.id} onClick={() => toggleTask(t.label)} className={`p-4 rounded-2xl border font-black text-[10px] uppercase transition-all flex items-center justify-center gap-2 ${t.checked ? 'bg-brand-600 border-brand-600 text-white shadow-lg' : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 text-slate-400'}`}>
                         {t.checked && <Check size={14}/>} {t.label}
                      </button>
                    ))}
                 </div>
              </div>

              <div className="p-8 bg-slate-50/30 dark:bg-slate-900/50">
                 <div className="flex justify-between items-center mb-5">
                    <h5 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Venda na Visita</h5>
                    <div className="text-xl font-black text-brand-600 tabular-nums">
                      R$ {parseFloat(uiState?.saleValue || '0').toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                    </div>
                 </div>

                 <div className="flex gap-2 mb-5">
                    <input type="number" placeholder="0,00" value={currentSaleInput} onChange={e => setCurrentSaleInput(e.target.value)} className="flex-1 p-4 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-2xl text-base font-black outline-none focus:ring-2 focus:ring-brand-500" />
                 </div>

                 <div className="grid grid-cols-2 gap-3 mb-6">
                    <button onClick={() => handleAddSale('palm')} className="py-4 bg-slate-900 text-white rounded-2xl font-black text-[10px] uppercase flex flex-col items-center gap-1 shadow-lg active:scale-95 transition-transform">+ PALM</button>
                    <button onClick={() => handleAddSale('site')} className="py-4 bg-brand-600 text-white rounded-2xl font-black text-[10px] uppercase flex flex-col items-center gap-1 shadow-lg active:scale-95 transition-transform">+ SITE</button>
                 </div>

                 {history.length > 0 && (
                   <div className="space-y-2">
                     <div className="flex justify-between items-center mb-2">
                        <span className="text-[9px] font-black text-slate-400 uppercase">Lançamentos</span>
                        <button onClick={handleClearSales} className="text-[9px] font-black text-red-500 uppercase hover:underline">Limpar</button>
                     </div>
                     <div className="max-h-32 overflow-y-auto space-y-2 pr-1 custom-scrollbar">
                        {history.map((op, idx) => (
                          <div key={idx} className="flex justify-between items-center bg-white dark:bg-slate-800 p-3 rounded-xl border border-slate-100 dark:border-slate-700">
                             <span className="text-[10px] font-black text-slate-600 dark:text-slate-400">PEDIDO #{idx + 1} ({parseFloat(op.palm) > 0 ? 'PALM' : 'SITE'})</span>
                             <span className="text-[10px] font-black text-brand-600 dark:text-brand-400">R$ {parseFloat(parseFloat(op.palm) > 0 ? op.palm : op.site).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                          </div>
                        ))}
                     </div>
                   </div>
                 )}
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

