    color: 'text-purple-500 bg-purple-50 dark:bg-purple-900/20',
    borderColor: 'border-purple-200 dark:border-purple-800',
    description: 'Produtos de alto valor agregado para clientes classe A.',
    items: [
      { productName: 'CAFE MELITTA 500G', quantity: 60, unitPrice: 15.90 },
      { productName: 'TORRADA BAUDUCCO INTEGRAL', quantity: 36, unitPrice: 6.50 }
    ]
  }
];

interface NegotiationHistoryItem {
  id: string;
  timestamp: number;
  clientName: string;
  productName: string;
  price: number;
  quantity: number;
  type: 'bonus' | 'discount';
  bonusQty: number;
  bonusType: 'same' | 'different';
  bonusProduct: string;
  bonusProductPrice: number;
  targetPrice: number;
}

interface ComboItem {
  id: string;
  productName: string;
  quantity: number;
  unitPrice: number;
  suggestedResalePrice?: number;
}

interface Combo {
  id: string;
  name: string;
  tag?: string;
  items: ComboItem[];
  totalValue: number;
}

export const Negotiate: React.FC = () => {
  const { state } = useStore();
  const [activeTab, setActiveTab] = useState<'generator' | 'combos'>('generator');
  const [history, setHistory] = useState<NegotiationHistoryItem[]>([]);
  const [combos, setCombos] = useState<Combo[]>([]);
  const [isCreatingCombo, setIsCreatingCombo] = useState(false);

  const [selectedClient, setSelectedClient] = useState<Client | null>(null);
  const [clientSearch, setClientSearch] = useState('');
  const [isClientDropdownOpen, setIsClientDropdownOpen] = useState(false);
  const [isProductDropdownOpen, setIsProductDropdownOpen] = useState(false);
  const [productName, setProductName] = useState(''); 
  const [quantity, setQuantity] = useState('');
  const [pricePalm, setPricePalm] = useState('');
  const [negotiationType, setNegotiationType] = useState<'bonus' | 'discount'>('bonus');
  const [bonusType, setBonusType] = useState<'same' | 'different'>('same');
  const [bonusProduct, setBonusProduct] = useState(''); 
  const [bonusQty, setBonusQty] = useState('');
  const [bonusProductPrice, setBonusProductPrice] = useState('');
  const [targetPrice, setTargetPrice] = useState('');
  const [generatedText, setGeneratedText] = useState('');
  const [copySuccess, setCopySuccess] = useState(false);
  const [comboCopySuccess, setComboCopySuccess] = useState<string | null>(null);

  const [newComboName, setNewComboName] = useState('');
  const [newComboTag, setNewComboTag] = useState('MIX');
  const [newComboItems, setNewComboItems] = useState<ComboItem[]>([
    { id: '1', productName: '', quantity: 1, unitPrice: 0, suggestedResalePrice: 0 }
  ]);

  const clientDropdownRef = useRef<HTMLDivElement>(null);
  const productDropdownRef = useRef<HTMLDivElement>(null);
  const resultRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const savedHist = localStorage.getItem('metacheck_negotiation_history');
    if (savedHist) setHistory(JSON.parse(savedHist));
    const savedCombos = localStorage.getItem('metacheck_combos');
    if (savedCombos) setCombos(JSON.parse(savedCombos));
  }, []);

  const filteredClients = useMemo(() => {
    if (!clientSearch) return state.clients.slice(0, 5);
    return state.clients.filter(c => 
      c.name.toLowerCase().includes(clientSearch.toLowerCase()) || 
      c.code.includes(clientSearch)
    ).slice(0, 10);
  }, [state.clients, clientSearch]);

  const smartProducts = useMemo(() => {
    const historyMap = new Map();
    history.forEach(h => {
      if (!historyMap.has(h.productName)) {
        historyMap.set(h.productName, { name: h.productName, price: h.price, source: 'history', lastDate: h.timestamp });
      }
    });
    QUICK_PRODUCTS.forEach(qp => {
      const fullName = `${qp.code} - ${qp.name}`;
      if (!historyMap.has(fullName)) {
        historyMap.set(fullName, { name: fullName, price: qp.price, source: 'catalog', lastDate: 0 });
      }
    });
    let all = Array.from(historyMap.values());
    if (productName) all = all.filter(p => p.name.toLowerCase().includes(productName.toLowerCase()));
    return all.sort((a, b) => b.lastDate - a.lastDate).slice(0, 8);
  }, [productName, history]);

  const genStats = useMemo(() => {
    const qty = parseFloat(quantity) || 0;
    const price = parseFloat(pricePalm.replace(',', '.')) || 0;
    const totalValueSystem = qty * price;
    let finalPrice = price;
    let investmentPercent = 0;
    let diffValueTotal = 0;

    if (negotiationType === 'bonus') {
      const bQty = parseFloat(bonusQty) || 0;
      if (bonusType === 'same') {
        // Bonificação do mesmo produto: Diluição do custo total pela quantidade total (vendida + bonificada)
        finalPrice = (qty + bQty) > 0 ? (qty * price) / (qty + bQty) : price;
        diffValueTotal = bQty * price;
        investmentPercent = (qty + bQty) > 0 ? (bQty / (qty + bQty)) * 100 : 0; 
      } else {
        // Bonificação de produto diferente: O valor do brinde é considerado um desconto no produto principal
        const otherPrice = parseFloat(bonusProductPrice.replace(',', '.')) || 0;
        diffValueTotal = bQty * otherPrice;
        finalPrice = qty > 0 ? (totalValueSystem - diffValueTotal) / qty : price;
        investmentPercent = totalValueSystem > 0 ? (diffValueTotal / totalValueSystem) * 100 : 0;
      }
    } else {
      // Desconto Direto: Preço de tabela vs Preço Alvo
      const target = parseFloat(targetPrice.replace(',', '.')) || price;
      finalPrice = target;
      investmentPercent = price > 0 ? ((price - target) / price) * 100 : 0;
      diffValueTotal = (price - target) * qty; 
    }
    return { totalValueSystem, finalPrice, investmentPercent, diffValueTotal };
  }, [quantity, pricePalm, bonusQty, targetPrice, negotiationType, bonusType, bonusProductPrice]);

  const handleGenerate = () => {
    if (!selectedClient) return alert("Selecione um cliente");
    if (!productName) return alert("Informe o produto");
    if (!quantity || !pricePalm) return alert("Informe quantidade e preço");

    const formatCurrency = (val: number) => val.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });

    const isBonus = negotiationType === 'bonus';
    let text = "";

    if (isBonus) {
      text = "🛒 *PROPOSTA COMERCIAL*\n\n" +
             `*Cliente:* ${selectedClient.name}\n` +
             `*Produto:* ${productName.toUpperCase()}\n` +
             `*Qtd Compra:* ${quantity} un.\n` +
             `*Preço Tabela:* R$ ${formatCurrency(parseFloat(pricePalm))}\n` +
             `*Valor do Pedido:* R$ ${formatCurrency(genStats.totalValueSystem)}\n\n` +
             "*CONDIÇÃO ESPECIAL*\n" +
             `*Bonificação:* ${bonusQty} un. ${bonusType === 'same' ? 'do mesmo item' : 'de ' + bonusProduct.toUpperCase()}\n` +
             `*Investimento em Brinde:* R$ ${formatCurrency(genStats.diffValueTotal)}\n` +
             `*Desconto Equivalente:* ${genStats.investmentPercent.toFixed(1).replace('.', ',')}% \n` +
             "--------------------------\n" +
             `💰 *PREÇO MÉDIO FINAL: R$ ${formatCurrency(genStats.finalPrice)}*\n` +
             "--------------------------";
    } else {
      text = "🛒 *PROPOSTA COMERCIAL*\n\n" +
             `*Cliente:* ${selectedClient.name}\n` +
             `*Produto:* ${productName.toUpperCase()}\n` +
             `*Qtd:* ${quantity} un.\n` +
             `*Preço Tabela:* R$ ${formatCurrency(parseFloat(pricePalm))}\n\n` +
             "*CONDIÇÃO ESPECIAL*\n" +
             `*Desconto direto para:* R$ ${formatCurrency(parseFloat(targetPrice))}\n` +
             `*Economia Total:* R$ ${formatCurrency(genStats.diffValueTotal)}\n` +
             `*Desconto aplicado:* ${genStats.investmentPercent.toFixed(1).replace('.', ',')}%\n` +
             "--------------------------\n" +
             `💰 *PREÇO FINAL: R$ ${formatCurrency(genStats.finalPrice)}*\n` +
             "--------------------------";
    }

    setGeneratedText(text);

    const newItem: NegotiationHistoryItem = { 
      id: Date.now().toString(), 
      timestamp: Date.now(), 
      clientName: selectedClient.name, 
      productName, 
      price: parseFloat(pricePalm), 
      quantity: parseInt(quantity), 
      type: negotiationType, 
      bonusQty: parseInt(bonusQty || '0'), 
      bonusType, 
      bonusProduct, 
      bonusProductPrice: parseFloat(bonusProductPrice || '0'), 
      targetPrice: parseFloat(targetPrice || '0') 
    };
    const newHist = [newItem, ...history].slice(0, 20);
    setHistory(newHist);
    localStorage.setItem('metacheck_negotiation_history', JSON.stringify(newHist));

    setTimeout(() => {
        resultRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }, 100);
  };

  const applyStrategicSuggestion = (suggestion: typeof STRATEGIC_SUGGESTIONS[0]) => {
    setIsCreatingCombo(true);
    setNewComboName(suggestion.name);
    setNewComboTag(suggestion.tag);
    setNewComboItems(suggestion.items.map((it, idx) => ({
      id: idx.toString(),
      productName: it.productName,
      quantity: it.quantity,
      unitPrice: it.unitPrice,
      suggestedResalePrice: Math.round(it.unitPrice * 1.35 * 100) / 100
    })));
  };

  const saveCombo = () => {
    if (!newComboName) return alert("Dê um nome ao combo");
    const combo: Combo = { 
      id: Date.now().toString(), 
      name: newComboName, 
      tag: newComboTag,
      items: newComboItems.filter(i => i.productName), 
      totalValue: newComboItems.reduce((a, b) => a + (b.quantity * b.unitPrice), 0) 
    };
    const updated = [combo, ...combos];
    setCombos(updated);
    localStorage.setItem('metacheck_combos', JSON.stringify(updated));
    setIsCreatingCombo(false);
    setNewComboName('');
    setNewComboTag('MIX');
    setNewComboItems([{ id: '1', productName: '', quantity: 1, unitPrice: 0, suggestedResalePrice: 0 }]);
  };

  const deleteCombo = (id: string) => {
    const updated = combos.filter(c => c.id !== id);
    setCombos(updated);
    localStorage.setItem('metacheck_combos', JSON.stringify(updated));
  };

  const copyCombo = (combo: Combo) => {
    const itemsText = combo.items.map(it => {
      const resaleInfo = it.suggestedResalePrice ? ` (Sug. Venda: R$ ${it.suggestedResalePrice.toLocaleString('pt-BR', { minimumFractionDigits: 2 })})` : '';
      return `• ${it.quantity}x ${it.productName}: R$ ${it.unitPrice.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}${resaleInfo}`;
    }).join('\n');

    const text = `📦 *COMBO: ${combo.name.toUpperCase()}*\n🎯 Objetivo: ${combo.tag || 'Mix'}\n\n${itemsText}\n\n*Total Investimento: R$ ${combo.totalValue.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}*`;
    navigator.clipboard.writeText(text);
  };

  const updateComboItem = (id: string, field: keyof ComboItem, value: any) => {
    setNewComboItems(prev => prev.map(item => item.id === id ? { ...item, [field]: value } : item));
  };

  const handleRemoveComboItem = (id: string) => {
    if (newComboItems.length > 1) {
      setNewComboItems(prev => prev.filter(item => item.id !== id));
    }
  };

  const getTagColor = (tag: string) => {
    switch(tag) {
      case 'GIRO': return 'bg-amber-100 text-amber-700 border-amber-200 dark:bg-amber-900/30 dark:text-amber-300 dark:border-amber-800';
      case 'MARGEM': return 'bg-emerald-100 text-emerald-700 border-emerald-200 dark:bg-emerald-900/30 dark:text-emerald-300 dark:border-emerald-800';
      case 'MIX': return 'bg-blue-100 text-blue-700 border-blue-200 dark:bg-blue-900/30 dark:text-blue-300 dark:border-blue-800';
      default: return 'bg-slate-100 text-slate-700 border-slate-200';
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6 animate-in fade-in duration-300 pb-32">
      <div className="flex flex-col gap-4">
        <div>
          <h2 className="text-2xl font-black text-slate-900 dark:text-white flex items-center gap-2 tracking-tighter">
            <Handshake className="text-brand-600" /> Negociação
          </h2>
          <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest mt-1">Simulador de Ofertas Estratégicas</p>
        </div>
        <div className="flex bg-slate-100 dark:bg-slate-800 p-1 rounded-2xl shadow-inner w-full">
          <button onClick={() => setActiveTab('generator')} className={`flex-1 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'generator' ? 'bg-white dark:bg-slate-700 text-brand-600 shadow-sm' : 'text-slate-400'}`}>Simulador</button>
          <button onClick={() => setActiveTab('combos')} className={`flex-1 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'combos' ? 'bg-white dark:bg-slate-700 text-brand-600 shadow-sm' : 'text-slate-400'}`}>Estratégias</button>
        </div>
      </div>

      {activeTab === 'generator' && (
        <div className="flex flex-col gap-6">
          <div className="space-y-4">
            {/* PDV Selector */}
            <div className="bg-white dark:bg-slate-900 p-5 rounded-[2rem] border border-slate-200 dark:border-slate-800 shadow-sm relative z-30">
              <label className="text-[9px] font-black text-slate-400 uppercase mb-2 block tracking-widest">Ponto de Venda</label>
              <div className="relative">
                <Search size={16} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-slate-400" />
                <input 
                  type="text" 
                  value={clientSearch} 
                  onChange={(e) => { setClientSearch(e.target.value); setIsClientDropdownOpen(true); }} 
                  onFocus={() => setIsClientDropdownOpen(true)} 
                  className="w-full pl-10 pr-4 py-3 bg-slate-50 dark:bg-slate-950 border-none rounded-2xl outline-none focus:ring-2 focus:ring-brand-500 text-sm font-black" 
                  placeholder="Pesquisar cliente..." 
                />
                {isClientDropdownOpen && (
                  <div className="absolute top-full left-0 right-0 mt-2 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl shadow-2xl max-h-48 overflow-y-auto z-40">
                    {filteredClients.map(c => (
                      <button key={c.id} onClick={() => { setSelectedClient(c); setClientSearch(c.name); setIsClientDropdownOpen(false); }} className="w-full text-left px-4 py-3 hover:bg-slate-50 dark:hover:bg-slate-800 border-b border-slate-100 dark:border-slate-800 last:border-0 transition-colors">
                        <p className="font-black text-xs text-slate-900 dark:text-white uppercase truncate">{c.name}</p>
                        <p className="text-[10px] font-bold text-slate-400">COD: {c.code}</p>
                      </button>
                    ))}
                  </div>
                )}
              </div>
            </div>

            {/* Product & Price Table */}
            <div className="bg-white dark:bg-slate-900 p-5 rounded-[2rem] border border-slate-200 dark:border-slate-800 shadow-sm relative z-20">
              <label className="text-[9px] font-black text-slate-400 uppercase mb-2 block tracking-widest">Produto e Tabela</label>
              <div className="relative">
                <input 
                  type="text" 
                  value={productName} 
                  onChange={(e) => { setProductName(e.target.value); setIsProductDropdownOpen(true); }} 
                  onFocus={() => setIsProductDropdownOpen(true)} 
                  className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-950 border-none rounded-2xl outline-none focus:ring-2 focus:ring-brand-500 text-sm font-black uppercase" 
                  placeholder="Nome do SKU..." 
                />
                {isProductDropdownOpen && (
                  <div className="absolute top-full left-0 right-0 mt-2 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl shadow-2xl max-h-48 overflow-y-auto z-40">
                    {smartProducts.map((p, i) => (
                      <button key={i} onClick={() => { setProductName(p.name); setPricePalm(p.price.toString()); setIsProductDropdownOpen(false); }} className="w-full text-left px-4 py-3 hover:bg-slate-50 dark:hover:bg-slate-800 border-b border-slate-100 dark:border-slate-800 last:border-0 flex justify-between items-center">
                        <div className="min-w-0 pr-2">
                           <p className="font-black text-[11px] text-slate-700 dark:text-slate-300 truncate uppercase">{p.name}</p>
                           {p.source === 'history' && <span className="text-[8px] font-black bg-amber-100 text-amber-700 px-1 rounded">ULTIMA NEGOC.</span>}
                        </div>
                        <span className="text-xs font-black text-emerald-600">R$ {p.price.toFixed(2)}</span>
                      </button>
                    ))}
                  </div>
                )}
              </div>
              <div className="grid grid-cols-2 gap-3 mt-4">
                <div className="space-y-1">
                   <span className="text-[9px] font-black text-slate-400 uppercase ml-1">Volume Compra</span>
                   <input type="number" placeholder="0" value={quantity} onChange={(e) => setQuantity(e.target.value)} className="w-full p-3 bg-slate-50 dark:bg-slate-950 border-none rounded-2xl text-sm font-black outline-none focus:ring-2 focus:ring-brand-500" />
                </div>
                <div className="space-y-1">
                   <span className="text-[9px] font-black text-slate-400 uppercase ml-1">Preço Tabela (R$)</span>
                   <input type="number" step="0.01" placeholder="0,00" value={pricePalm} onChange={(e) => setPricePalm(e.target.value)} className="w-full p-3 bg-slate-50 dark:bg-slate-950 border-none rounded-2xl text-sm font-black outline-none focus:ring-2 focus:ring-brand-500" />
                </div>
              </div>
            </div>

            {/* Condition Panel */}
            <div className="bg-slate-950 p-6 rounded-[2.5rem] shadow-xl text-white">
              <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-3 mb-6">
                <h3 className="text-[10px] font-black text-brand-400 uppercase tracking-[0.2em]">Cálculo de Investimento</h3>
                <div className="flex bg-white/10 p-1 rounded-xl w-full sm:w-auto">
                  <button onClick={() => setNegotiationType('bonus')} className={`flex-1 sm:flex-none px-4 py-2 rounded-lg text-[10px] font-black uppercase transition-all ${negotiationType === 'bonus' ? 'bg-brand-500 text-white shadow-lg' : 'text-slate-400'}`}>Bonificar</button>
                  <button onClick={() => setNegotiationType('discount')} className={`flex-1 sm:flex-none px-4 py-2 rounded-lg text-[10px] font-black uppercase transition-all ${negotiationType === 'discount' ? 'bg-brand-500 text-white shadow-lg' : 'text-slate-400'}`}>Desconto</button>
                </div>
              </div>

              {negotiationType === 'bonus' ? (
                <div className="space-y-4">
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                    <div className="space-y-1">
                       <span className="text-[10px] font-black text-slate-400 uppercase ml-1">Bonificação (Unidades)</span>
                       <input type="number" placeholder="0" value={bonusQty} onChange={(e) => setBonusQty(e.target.value)} className="w-full p-4 bg-white/10 border border-white/10 rounded-2xl text-2xl font-black outline-none focus:border-brand-500 tabular-nums" />
                    </div>
                    <div className="space-y-1">
                       <span className="text-[10px] font-black text-slate-400 uppercase ml-1">Tipo de Brinde</span>
                       <select value={bonusType} onChange={(e) => setBonusType(e.target.value as any)} className="w-full p-4 bg-white/10 border border-white/10 rounded-2xl text-sm font-black outline-none h-[64px] uppercase">
                          <option value="same">Mesmo Produto</option>
                          <option value="different">Outro Item</option>
                       </select>
                    </div>
                  </div>

                  {bonusType === 'different' && (
                    <div className="grid grid-cols-2 gap-4 animate-in fade-in">
                       <div className="space-y-1">
                         <span className="text-[9px] font-black text-slate-400 uppercase ml-1">Produto Brinde</span>
                         <input value={bonusProduct} onChange={e => setBonusProduct(e.target.value)} placeholder="Nome SKU" className="w-full p-3 bg-white/10 border border-white/10 rounded-xl text-xs font-black outline-none" />
                       </div>
                       <div className="space-y-1">
                         <span className="text-[9px] font-black text-slate-400 uppercase ml-1">Preço Brinde</span>
                         <input type="number" step="0.01" value={bonusProductPrice} onChange={e => setBonusProductPrice(e.target.value)} placeholder="0,00" className="w-full p-3 bg-white/10 border border-white/10 rounded-xl text-xs font-black outline-none" />
                       </div>
                    </div>
                  )}

                  <div className="flex justify-between items-center border-t border-white/10 pt-4">
                    <span className="text-[10px] text-slate-400 font-black uppercase">Diluição (Custo Médio)</span>
                    <span className="text-3xl font-black text-emerald-400 tabular-nums tracking-tighter">R$ {genStats.finalPrice.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                  </div>
                </div>
              ) : (
                <div className="space-y-4">
                  <div className="space-y-1">
                     <span className="text-[10px] font-black text-slate-400 uppercase ml-1">Preço Alvo Desejado (R$)</span>
                     <input type="number" step="0.01" placeholder="0,00" value={targetPrice} onChange={(e) => setTargetPrice(e.target.value)} className="w-full p-4 bg-white/10 border border-white/10 rounded-2xl text-2xl font-black outline-none focus:border-brand-500 tabular-nums" />
                  </div>
                  <div className="flex justify-between items-center border-t border-white/10 pt-4">
                    <span className="text-[10px] text-slate-400 font-black uppercase">Percentual de Desconto</span>
                    <span className="text-3xl font-black text-emerald-400 tabular-nums tracking-tighter">{genStats.investmentPercent.toFixed(1).replace('.', ',')}%</span>
                  </div>
                </div>
              )}
            </div>

            <button 
                onClick={handleGenerate} 
                className="w-full bg-brand-600 hover:bg-brand-700 text-white font-black py-5 rounded-[2rem] shadow-2xl shadow-brand-500/20 flex items-center justify-center gap-3 transition-all active:scale-[0.98] uppercase text-xs tracking-widest"
            >
                <FileText size={20} /> Gerar Proposta Comercial
            </button>
          </div>

          {/* Copy Area */}
          <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] border border-slate-200 dark:border-slate-800 shadow-sm flex flex-col min-h-[380px] overflow-hidden" ref={resultRef}>
            <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex justify-between items-center bg-slate-50/50 dark:bg-slate-950/50">
                <div className="flex items-center gap-2">
                    <div className="p-2 bg-brand-50 dark:bg-brand-900/20 text-brand-600 rounded-xl"><Repeat size={18} /></div>
                    <h3 className="font-black text-[10px] text-slate-500 uppercase tracking-widest">Resumo Comercial (WhatsApp)</h3>
                </div>
                <button 
                    onClick={() => { navigator.clipboard.writeText(generatedText); setCopySuccess(true); setTimeout(() => setCopySuccess(false), 2000); }} 
                    disabled={!generatedText} 
                    className={`p-3 rounded-2xl transition-all ${copySuccess ? 'text-emerald-500 bg-emerald-50' : 'text-slate-400 bg-slate-100 dark:bg-slate-800 hover:text-brand-600 active:scale-90 disabled:opacity-30'}`}
                >
                    {copySuccess ? <Check size={20} /> : <Copy size={20} />}
                </button>
            </div>
            <textarea 
                readOnly 
                value={generatedText} 
                className="flex-1 p-8 outline-none bg-transparent text-sm font-black text-slate-800 dark:text-slate-300 resize-none leading-relaxed custom-scrollbar" 
                placeholder="Configure o simulador acima para gerar a proposta comercial..." 
            />
          </div>
        </div>
      )}

      {activeTab === 'combos' && (
        <div className="animate-in fade-in space-y-8">
