                          <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{c.items.length} SKUs no Mix</p>
                       </div>
                       <div className="flex gap-1.5">
                          <button onClick={() => deleteCombo(c.id)} className="p-2.5 text-slate-300 hover:text-red-500 transition-colors"><Trash2 size={18} /></button>
