                            onClick={() => { copyCombo(c); setComboCopySuccess(c.id); setTimeout(() => setComboCopySuccess(null), 2000); }} 
                            className={`p-3 rounded-2xl transition-all ${comboCopySuccess === c.id ? 'bg-emerald-50 text-emerald-600' : 'bg-slate-50 dark:bg-slate-800 text-slate-500 hover:text-brand-600 active:scale-90 shadow-sm'}`}
