                <div className="space-y-4">
                   <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-2 mb-2">Itens do Mix</div>
                   {newComboItems.map(item => (
                     <div key={item.id} className="bg-slate-50 dark:bg-slate-950/50 p-6 rounded-[2rem] border border-slate-100 dark:border-slate-800 space-y-4 relative group">
                        <div className="flex justify-between items-start gap-4">
                           <div className="flex-1">
                               <label className="text-[9px] font-black text-slate-400 uppercase mb-1.5 block">Nome do SKU</label>
                               <input value={item.productName} onChange={e => updateComboItem(item.id, 'productName', e.target.value)} placeholder="Produto" className="w-full p-3 bg-white dark:bg-slate-900 border-none rounded-xl text-xs font-black uppercase outline-none focus:ring-2 focus:ring-brand-500" />
                           </div>
                           <button onClick={() => handleRemoveComboItem(item.id)} className="mt-7 p-2.5 text-slate-300 hover:text-red-500 transition-colors"><Trash2 size={18}/></button>
                        </div>

                        <div className="grid grid-cols-3 gap-3">
                           <div>
                               <label className="text-[9px] font-black text-slate-400 uppercase mb-1.5 block text-center">Qtd</label>
                               <input type="number" value={item.quantity} onChange={e => updateComboItem(item.id, 'quantity', parseFloat(e.target.value) || 0)} className="w-full p-3 bg-white dark:bg-slate-900 border-none rounded-xl text-xs text-center font-black outline-none focus:ring-2 focus:ring-brand-500" />
                           </div>
                           <div>
                               <label className="text-[9px] font-black text-slate-400 uppercase mb-1.5 block">Preço (R$)</label>
                               <input type="number" step="0.01" value={item.unitPrice} onChange={e => updateComboItem(item.id, 'unitPrice', parseFloat(e.target.value) || 0)} className="w-full p-3 bg-white dark:bg-slate-900 border-none rounded-xl text-xs font-black outline-none focus:ring-2 focus:ring-brand-500" />
                           </div>
                           <div>
                               <label className="text-[9px] font-black text-emerald-500 uppercase mb-1.5 block">Sug. Venda</label>
                               <input type="number" step="0.01" value={item.suggestedResalePrice} onChange={e => updateComboItem(item.id, 'suggestedResalePrice', parseFloat(e.target.value) || 0)} className="w-full p-3 bg-emerald-50 dark:bg-emerald-900/20 border-none rounded-xl text-xs font-black text-emerald-600 outline-none focus:ring-2 focus:ring-emerald-500" />
                           </div>
                        </div>
                     </div>
                   ))}

                   <button 
                      onClick={() => setNewComboItems([...newComboItems, { id: Date.now().toString(), productName: '', quantity: 1, unitPrice: 0, suggestedResalePrice: 0 }])} 
                      className="w-full py-5 border-2 border-dashed border-slate-200 dark:border-slate-800 rounded-[2rem] text-[10px] font-black uppercase tracking-widest text-slate-400 hover:text-brand-600 hover:border-brand-500 transition-all flex items-center justify-center gap-2"
                   >
                      <Plus size={18} strokeWidth={3} /> Adicionar SKU
                   </button>
                </div>

                <div className="flex flex-col md:flex-row justify-between items-center gap-6 pt-8 border-t border-slate-100 dark:border-slate-800">
                    <div className="text-center md:text-left">
                       <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Valor do Mix</p>
                       <p className="text-4xl font-black text-brand-600 tabular-nums tracking-tighter">R$ {newComboItems.reduce((a, b) => a + (b.quantity * b.unitPrice), 0).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
                    </div>
                    <div className="flex gap-3 w-full md:w-auto">
                        <button onClick={() => setIsCreatingCombo(false)} className="flex-1 px-8 py-4 text-xs font-black uppercase tracking-widest text-slate-500 bg-slate-100 dark:bg-slate-800 rounded-2xl active:scale-[0.98]">Cancelar</button>
                        <button onClick={saveCombo} className="flex-1 bg-brand-600 text-white px-10 py-4 rounded-2xl font-black text-xs uppercase tracking-widest shadow-2xl shadow-brand-500/20 active:scale-[0.98]">Salvar Estratégia</button>
                    </div>
                </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

